request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?reqName ?specType ?timeExprName WHERE {
  ?aps vocab:NamedElement_name ?apsName .
  FILTER(CONTAINS(LCASE(STR(?apsName)), LCASE("aps")))

  ?req rdf:type vocab:tmt%20requirement .
  OPTIONAL { ?req vocab:NamedElement_name ?reqName }

  # Find timing-related constraints/specifications connected to requirement
  ?req vocab:constraint ?constr .
  BIND(?constr AS ?spec)
  OPTIONAL { ?spec rdf:type ?specType }

  OPTIONAL {
    ?spec vocab:owningConstraint ?timeSpec .
    ?timeSpec vocab:NamedElement_name ?timeExprName .
  }

  FILTER( EXISTS {
    ?spec rdf:type vocab:Duration%20constraint .
  } || EXISTS {
    ?spec rdf:type vocab:Time%20constraint .
  } || EXISTS {
    ?spec vocab:expression ?expr .
  })
}
LIMIT 25
